from __future__ import annotations

from collections import defaultdict
from functools import lru_cache
from typing import TYPE_CHECKING

from cloud.costengine.enums import CostCategory, HardwareCategory, ItemType, ServiceCategory, SpecialCategory
from cloud.location.enums import Country
from cloud.products.enums import ProductCategory as ProductProductCategory
from cloud.shoppingcart.product_tree.enums import ProductCategory

if TYPE_CHECKING:
    from cloud.costengine.models import CostItem
    from cloud.shoppingcart.models import ShoppingCart


# This mapping should never change.
# If cost items needs to be moved, the product category node should be moved instead.
COST_TO_PRODUCT_MAPPING: dict[CostCategory, ProductCategory] = {
    # Special
    SpecialCategory.INSTALLER_MARKUP: ProductCategory.ALL,
    SpecialCategory.COST_MODIFICATION: ProductCategory.ALL,
    # Hardware: Panel
    HardwareCategory.PANEL_HARDWARE: ProductCategory.HARDWARE_PANEL,
    # Hardware: Inverter
    HardwareCategory.INVERTER_HARDWARE: ProductCategory.HARDWARE_INVERTER,
    # Hardware: Battery
    HardwareCategory.BATTERY_HARDWARE: ProductCategory.HARDWARE_BATTERY,
    # Hardware: Smart meter
    HardwareCategory.SMART_METER_HARDWARE: ProductCategory.HARDWARE_SMART_METER,
    # Hardware: EV charger
    HardwareCategory.EV_CHARGER_HARDWARE: ProductCategory.HARDWARE_EV_CHARGER,
    # Hardware: DC optimizers
    HardwareCategory.DC_OPTIMIZERS_HARDWARE: ProductCategory.HARDWARE_DC_OPTIMIZER,
    # Hardware: Panel mounting
    HardwareCategory.MOUNTING_MATERIALS: ProductCategory.HARDWARE_MOUNTING_MATERIAL,
    HardwareCategory.MOUNTING_MATERIALS_HORIZONTAL_MOUNTING_PREMIUM: ProductCategory.HARDWARE_MOUNTING_MATERIAL,
    HardwareCategory.MOUNTING_MATERIALS_SNOW_LOAD_PREMIUM: ProductCategory.HARDWARE_MOUNTING_MATERIAL,
    # Hardware AC Cable
    HardwareCategory.INVERTER_ELECTRICIAN_ADDITIONAL_AC_CABLE: ProductCategory.HARDWARE_INVERTER_AC_CABLE,
    # Hardware: DC cable
    HardwareCategory.DC_CABLE_HARDWARE: ProductCategory.HARDWARE_DC_CABLE,
    HardwareCategory.DC_CABLE_ADDITIONAL_METER: ProductCategory.HARDWARE_DC_CABLE,
    # Hardware: DC switches
    HardwareCategory.DC_SWITCHES_HARDWARE: ProductCategory.HARDWARE_DC_SWITCH,
    # Service: Panels
    ServiceCategory.PANEL_MOUNTING_WORK: ProductCategory.SERVICE_PANEL,
    ServiceCategory.PANEL_MOUNTING_WORK_ROOFING_PREMIUM: ProductCategory.SERVICE_PANEL,
    ServiceCategory.PANEL_MOUNTING_WORK_SNOWLOAD_PREMIUM: ProductCategory.SERVICE_PANEL,
    ServiceCategory.PANEL_MOUNTING_WORK_STARTUP: ProductCategory.SERVICE_PANEL,
    # Service: Inverters
    ServiceCategory.INVERTER_WORK: ProductCategory.SERVICE_INVERTER,
    ServiceCategory.INVERTER_ELECTRICIAN: ProductCategory.SERVICE_INVERTER,
    # Service: Battery
    ServiceCategory.BATTERY_WORK: ProductCategory.SERVICE_BATTERY,
    # Service: Smart meters
    ServiceCategory.SMART_METER_WORK: ProductCategory.SERVICE_SMART_METER,
    # Service: EV chargers
    ServiceCategory.EV_CHARGER_WORK: ProductCategory.SERVICE_EV_CHARGER,
    # Service: DC cables
    ServiceCategory.DC_CABLE_WORK: ProductCategory.SERVICE_DC_CABLE,
    # Service: DC switches
    ServiceCategory.DC_SWITCHES_WORK: ProductCategory.SERVICE_DC_SWITCH,
    # Service: Optimizers
    ServiceCategory.DC_OPTIMIZERS_WORK: ProductCategory.SERVICE_DC_OPTIMIZER,
    # Service: Scaffolding
    ServiceCategory.SCAFFOLDING: ProductCategory.SERVICE_SCAFFOLDING,
    # Service: Travel
    ServiceCategory.TRAVEL_PERSONNEL: ProductCategory.SERVICE_TRAVEL,
    ServiceCategory.TRAVEL_EQUIPMENT: ProductCategory.SERVICE_TRAVEL,
    # Service: Hub
    ServiceCategory.HUB_WORK: ProductCategory.SERVICE_HUB,
    ServiceCategory.HUB_ELECTRICIAN: ProductCategory.SERVICE_HUB,
    # Service: Extra
    ServiceCategory.PROJECT_STARTUP_COST: ProductCategory.SERVICE_OTHER,
    ServiceCategory.SYSTEM_SIZE_STARTUP_COST: ProductCategory.SERVICE_OTHER,
}

HARDWARE_TO_PRODUCT_MAPPING: dict[ProductCategory, ProductProductCategory] = {
    ProductCategory.HARDWARE_PANEL: ProductProductCategory.PANEL,
    ProductCategory.HARDWARE_MOUNTING_MATERIAL: ProductProductCategory.MOUNTING,
    ProductCategory.HARDWARE_INVERTER: ProductProductCategory.INVERTER,
    ProductCategory.HARDWARE_INVERTER_AC_CABLE: ProductProductCategory.INVERTER,
    ProductCategory.HARDWARE_BATTERY: ProductProductCategory.BATTERY,
    ProductCategory.HARDWARE_SMART_METER: ProductProductCategory.SMART_METER,
    ProductCategory.HARDWARE_EV_CHARGER: ProductProductCategory.EV_CHARGER,
    ProductCategory.HARDWARE_DC_CABLE: ProductProductCategory.DC_CABLE,
    ProductCategory.HARDWARE_DC_SWITCH: ProductProductCategory.DC_SWITCH,
    ProductCategory.HARDWARE_DC_OPTIMIZER: ProductProductCategory.OPTIMIZER,
}


@lru_cache(maxsize=128)
def get_legacy_product_for_product_category(
    product_category: ProductCategory, is_extra_item=False
) -> ProductProductCategory:
    if is_extra_item:
        return ProductProductCategory.OTHER
    elif ProductCategory in [ProductCategory.UNKNOWN, ProductCategory.ALL]:
        return ProductProductCategory.UNKNOWN
    elif product_category.value.startswith('service') or product_category.value.endswith('service'):
        return ProductProductCategory.SERVICE
    elif product_category.value.startswith(ProductCategory.PV.value):
        return ProductProductCategory.PV_SYSTEM
    elif product_category.value.startswith(ProductCategory.BATTERY.value):
        return ProductProductCategory.BATTERY
    elif product_category.value.startswith(ProductCategory.EV_CHARGER.value):
        return ProductProductCategory.EV_CHARGER
    elif category := HARDWARE_TO_PRODUCT_MAPPING.get(product_category):
        return category
    raise ValueError(f'cannot infer product_category for {product_category=}')


def get_product_category_to_cost_items_mapping(
    cost_items: list[CostItem],
) -> dict[ProductCategory, list[CostItem]]:
    product_to_cost_items_mapping = defaultdict(list)
    for cost_item in cost_items:
        if cost_item.item_type == ItemType.SPECIAL_PRODUCT:
            continue
        product_category = cost_item.shopping_cart_product_category
        product_to_cost_items_mapping[product_category].append(cost_item)

    return product_to_cost_items_mapping


def _get_market_override_mapping(shopping_cart: ShoppingCart) -> dict[ProductCategory, ProductCategory]:
    country = shopping_cart.business_unit.market
    if country == Country.SE and shopping_cart.has_batteries:
        return {
            ProductCategory.HARDWARE_INVERTER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_INVERTER_AC_CABLE: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_SMART_METER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_DC_CABLE: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_DC_SWITCH: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.SERVICE_INVERTER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_SMART_METER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_DC_CABLE: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_DC_SWITCH: ProductCategory.BATTERY_SERVICE,
        }
    return {}


def _get_hardware_override_mapping(shopping_cart: ShoppingCart) -> dict[ProductCategory, ProductCategory]:
    if shopping_cart.is_standalone_battery:
        return {
            ProductCategory.HARDWARE_INVERTER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_INVERTER_AC_CABLE: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_SMART_METER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.SERVICE_INVERTER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_SMART_METER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_TRAVEL: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_OTHER: ProductCategory.BATTERY_SERVICE,
        }
    return {}


def get_product_category_override_mapping(
    shopping_cart: ShoppingCart,
) -> dict[ProductCategory, ProductCategory]:
    return _get_hardware_override_mapping(shopping_cart) | _get_market_override_mapping(shopping_cart)
