@lru_cache(maxsize=128)
def get_legacy_product_for_product_category(
    product_category: ProductCategory, is_extra_item=False
) -> ProductProductCategory:
    if is_extra_item:
        return ProductProductCategory.OTHER
    elif product_category in [ProductCategory.UNKNOWN, ProductCategory.ALL]:
        return ProductProductCategory.UNKNOWN
    elif product_category.value.startswith('service') or product_category.value.endswith('service'):
        return ProductProductCategory.SERVICE
    elif product_category.value.startswith(ProductCategory.PV.value):
        return ProductProductCategory.PV_SYSTEM
    elif product_category.value.startswith(ProductCategory.BATTERY.value):
        return ProductProductCategory.BATTERY
    elif product_category.value.startswith(ProductCategory.EV_CHARGER.value):
        return ProductProductCategory.EV_CHARGER
    elif category := HARDWARE_TO_PRODUCT_MAPPING.get(product_category):
        return category
    raise ValueError(f'Cannot infer product_category for {product_category=}')

def get_product_category_to_cost_items_mapping(
    cost_items: list[CostItem],
) -> dict[ProductCategory, list[CostItem]]:
    product_to_cost_items_mapping = defaultdict(list)
    for cost_item in cost_items:
        if cost_item.item_type == ItemType.SPECIAL_PRODUCT:
            continue
        product_category = cost_item.shopping_cart_product_category
        product_to_cost_items_mapping[product_category].append(cost_item)

    return product_to_cost_items_mapping


def _get_market_override_mapping(shopping_cart: ShoppingCart) -> dict[ProductCategory, ProductCategory]:
    country = shopping_cart.business_unit.market
    if country == Country.SE and shopping_cart.has_batteries:
        return {
            ProductCategory.HARDWARE_INVERTER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_INVERTER_AC_CABLE: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_SMART_METER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_DC_CABLE: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_DC_SWITCH: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.SERVICE_INVERTER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_SMART_METER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_DC_CABLE: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_DC_SWITCH: ProductCategory.BATTERY_SERVICE,
        }
    return {}


def _get_hardware_override_mapping(shopping_cart: ShoppingCart) -> dict[ProductCategory, ProductCategory]:
    if shopping_cart.is_standalone_battery:
        return {
            ProductCategory.HARDWARE_INVERTER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_INVERTER_AC_CABLE: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.HARDWARE_SMART_METER: ProductCategory.BATTERY_HARDWARE,
            ProductCategory.SERVICE_INVERTER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_SMART_METER: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_TRAVEL: ProductCategory.BATTERY_SERVICE,
            ProductCategory.SERVICE_OTHER: ProductCategory.BATTERY_SERVICE,
        }
    return {}


def get_product_category_override_mapping(
    shopping_cart: ShoppingCart,
) -> dict[ProductCategory, ProductCategory]:
    return _get_hardware_override_mapping(shopping_cart) | _get_market_override_mapping(shopping_cart)
```

### Key Changes:
1. **Enum value access**: The `.value` of the enum is accessed before calling `startswith` or `endswith`.

2. **Enum membership check**: Corrected the improper check of `ProductCategory in [ProductCategory.Unknown, ...]`.

These changes should resolve the errors you mentioned.
